// ============================================================
// XLSX PARSER
// ============================================================
const parseExcel = async (file) => {
  if (!window.XLSX) {
    await new Promise((resolve, reject) => {
      const s = document.createElement("script");
      s.src = "https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js";
      s.onload = resolve; s.onerror = reject;
      document.head.appendChild(s);
    });
  }
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const wb = window.XLSX.read(e.target.result, { type: "array" });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const rows = window.XLSX.utils.sheet_to_json(ws, { header: 1 });
        let headerIdx = -1;
        for (let i = 0; i < Math.min(rows.length, 15); i++) {
          const row = rows[i];
          if (row && row.some(c => String(c).trim().toUpperCase() === "NO") && row.some(c => String(c).trim().toUpperCase() === "NAME")) { headerIdx = i; break; }
        }
        if (headerIdx === -1) { reject(new Error("Cannot find header row with NO and NAME columns.")); return; }
        const header = rows[headerIdx].map(c => String(c || "").trim().toUpperCase());
        const colMap = {};
        header.forEach((h, i) => {
          if (h === "NO") colMap.no = i;
          else if (h === "NAME") colMap.name = i;
          else if (h === "NO.KP" || h === "NO KP" || h === "IC" || h === "NOKP") colMap.ic = i;
          else if (h === "RD") colMap.rd = i;
          else if (h === "L") colMap.l = i;
          else if (h.startsWith("SP") && h.includes("ID")) colMap.spId = i;
          else if (h.startsWith("SP") && (h.includes("GP") || h.includes("GR"))) colMap.spGr = i;
          else if (h.startsWith("W") && h.includes("T1")) colMap.wT1 = i;
          else if (h.startsWith("W") && h.includes("T2")) colMap.wT2 = i;
        });
        const students = [];
        for (let i = headerIdx + 1; i < rows.length; i++) {
          const row = rows[i];
          if (!row || !row[colMap.name] || String(row[colMap.name]).trim() === "") continue;
          const name = String(row[colMap.name]).trim();
          if (name.toUpperCase() === "NAME") continue;
          const num = (idx) => { const v = row[colMap[idx]]; return typeof v === "number" ? v : parseFloat(v) || 0; };
          const ic = colMap.ic !== undefined ? String(row[colMap.ic] || "").trim() : "";
          const raw = { no: row[colMap.no] || students.length + 1, name, ic, rd: num("rd"), l: num("l"), spId: num("spId"), spGr: num("spGr"), wT1: num("wT1"), wT2: num("wT2") };
          students.push({ ...raw, ...calcScores(raw) });
        }
        if (students.length === 0) { reject(new Error("No student data found.")); return; }
        let teacherName = "", className = "";
        for (let i = 0; i < headerIdx; i++) {
          const row = rows[i]; if (!row) continue;
          const joined = row.map(c => String(c || "")).join(" ").toUpperCase();
          if (joined.includes("NAME:")) { const m = joined.match(/NAME:\s*(.+)/); if (m) teacherName = m[1].trim(); }
          if (joined.includes("CLASS:")) { const m = joined.match(/CLASS:\s*(.+)/); if (m) className = m[1].replace(/\./g, "").trim(); }
        }
        resolve({ students, meta: { teacherName, className }, hasIC: colMap.ic !== undefined });
      } catch (err) { reject(err); }
    };
    reader.onerror = () => reject(new Error("Failed to read file"));
    reader.readAsArrayBuffer(file);
  });
};

