// FILE DROP ZONE
// ============================================================
const FileDropZone = ({ onFile, file, loading, onClear }) => {
  const [drag, setDrag] = useState(false);
  const inputRef = useRef(null);
  const handleDrop = useCallback((e) => { e.preventDefault(); setDrag(false); const f = e.dataTransfer?.files?.[0]; if (f && (f.name.endsWith(".xlsx") || f.name.endsWith(".xls"))) onFile(f); }, [onFile]);
  return (
    <div onClick={() => { if (!file) inputRef.current?.click(); }}
      onDragOver={(e) => { e.preventDefault(); setDrag(true); }} onDragLeave={() => setDrag(false)} onDrop={handleDrop}
      style={{ border: `2px dashed ${drag ? colors.accent : colors.border}`, borderRadius: 14, padding: "24px 20px", textAlign: "center", cursor: file ? "default" : "pointer", transition: "all 0.2s", background: drag ? colors.accentLight : file ? "#F0FDF4" : colors.warm, position: "relative" }}>
      <input ref={inputRef} type="file" accept=".xlsx,.xls" onChange={(e) => { const f = e.target.files?.[0]; if (f) onFile(f); e.target.value = ""; }} style={{ display: "none" }} />
      {loading ? (
        <div style={{ fontFamily: font, color: colors.accent, fontSize: 15 }}>
          <div style={{ width: 32, height: 32, border: `3px solid ${colors.accentLight}`, borderTopColor: colors.accent, borderRadius: "50%", animation: "spin 0.8s linear infinite", margin: "0 auto 12px" }} />Reading file...
        </div>
      ) : file ? (
        <div style={{ fontFamily: font }}>
          <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke={colors.accent} strokeWidth="2" strokeLinecap="round" style={{ marginBottom: 8 }}><path d="M9 12l2 2 4-4" /><circle cx="12" cy="12" r="10" /></svg>
          <p style={{ fontSize: 15, fontWeight: 600, color: colors.accent, margin: 0 }}>{file.name}</p>
          <div style={{ display: "flex", gap: 16, justifyContent: "center", marginTop: 10 }}>
            <button onClick={(e) => { e.stopPropagation(); inputRef.current?.click(); }} style={{ fontFamily: font, fontSize: 12, fontWeight: 500, color: colors.accent, background: "none", border: `1px solid ${colors.accent}`, borderRadius: 6, padding: "5px 14px", cursor: "pointer" }}>Change file</button>
            <button onClick={(e) => { e.stopPropagation(); onClear(); }} style={{ fontFamily: font, fontSize: 12, fontWeight: 500, color: colors.error, background: "none", border: `1px solid ${colors.error}`, borderRadius: 6, padding: "5px 14px", cursor: "pointer" }}>Remove</button>
          </div>
        </div>
      ) : (
        <div style={{ fontFamily: font }}>
          <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke={colors.textMuted} strokeWidth="1.5" strokeLinecap="round" style={{ marginBottom: 12 }}><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4" /><polyline points="17 8 12 3 7 8" /><line x1="12" y1="3" x2="12" y2="15" /></svg>
          <p style={{ fontSize: 15, fontWeight: 500, color: colors.text, margin: 0 }}>Drag Excel file or click to upload</p>
          <p style={{ fontSize: 13, color: colors.textMuted, marginTop: 6 }}>.xlsx format only</p>
        </div>
      )}
    </div>
  );
};

